external_knowledge:
- "attract the most action in terms of places to visit" refers to boroughs with a high number of venues;
- "typical vibe" is reflected in the average ratings of the venues;
- "bustling business scene" indicates the total number of businesses;
- "area's crowd density" corresponds to the average population density;
- "type of establishment that dominates" is the most popular venue category based on the number of venues in that category.

sql:
SELECT review_text
FROM venue_reviews
WHERE user_id = 1 AND venue_id = 1;

SELECT borough_name
FROM boroughs
WHERE (population / area) > 2000.0;

SELECT venue_name
FROM venues
WHERE venue_id = 0;

SELECT neighborhood_id, COUNT(venue_id) AS total_venues
FROM venues
GROUP BY neighborhood_id;

SELECT category_name 
FROM venue_categories 
WHERE parent_category_id IS NULL;

SELECT borough_name 
FROM boroughs 
WHERE population > 10000;

external_knowledge:
'top-rated places' refers to venues with a rating greater than 4.0;
The summary should be organized by borough and venue type;
The income level, business density, and average reviews should give insights into the characteristics of highly-rated venues' neighborhoods;

sql:
SELECT review_text
FROM venue_reviews
WHERE venue_id IN (
    SELECT venue_id
    FROM venues
    WHERE rating = (
        SELECT MAX(rating) 
        FROM venues
    )
);

SELECT venue_name, phone_number 
FROM venues
WHERE rating < (
    SELECT AVG(rating) 
    FROM venues
);

SELECT neighborhoods.neighborhood_name, neighborhood_demographics.income_level
FROM neighborhoods
JOIN neighborhood_demographics ON neighborhoods.neighborhood_id = neighborhood_demographics.neighborhood_id;
